// ═══════════════════════════════════════════════════════════════
// NODO: Intellikey Unified Navigator (LEGEND VERSION)
// DESC: Navigazione dinamica con indicatore di stato e legenda
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;
const catalog = item.service_catalog_setup.categories || [];
const owner = item.owner_data || {};
const cbData = item.body.callback_query.data; 
const chatId = item.body.callback_query.message.chat.id;
const messageId = item.body.callback_query.message.message_id;

// 1. Rilevamento Lingua
const rawLang = (owner.lenguage || 'it').toLowerCase();
let lang = rawLang.includes('en') ? 'en' : 'it';

const t = {
  it: {
    root_title: "🗂️ <b>HUB AZIENDALE</b>",
    root_body: "Seleziona l'area di intervento:",
    cat_title: "📂 <b>CATEGORIE</b>",
    svc_title: "📋 <b>PROCEDURE</b>",
    btn_back: "⬅️ Torna Indietro",
    sop: "⚙️ PROCEDURE OPERATIVE",
    ser: "🛠️ SERVIZI OFFERTI",
    pro: "📦 PRODOTTI VENDUTI",
    legend: "\n\n<i>Legenda:\n🟢 Disponibile \n⚪ Da Attivare</i>"
  },
  en: {
    root_title: "🗂️ <b>BUSINESS HUB</b>",
    root_body: "Select the area of intervention:",
    cat_title: "📂 <b>CATEGORIES</b>",
    svc_title: "📋 <b>PROCEDURES</b>",
    btn_back: "⬅️ Back",
    sop: "⚙️ PROCEDURES (SOP)",
    ser: "🛠️ SERVICES (SER)",
    pro: "📦 PRODUCTS (PRO)",
    legend: "\n\n<i>Legend:\n🟢 Ready to use\n⚪ Activate</i>"
  }
}[lang];

let text = "";
let buttons = [];

// =============================================================================
// LIVELLO 1: ROOT (get_active)
// =============================================================================
if (cbData === "get_active") {
  text = `${t.root_title}\n━━━━━━━━━━━━━━━━━━━━\n${t.root_body}`;
  buttons = [
    [{ text: t.sop, callback_data: "get_active_sop" }],
    [{ text: t.ser, callback_data: "get_active_ser" }],
    [{ text: t.pro, callback_data: "get_active_pro" }],
    [{ text: t.btn_back, callback_data: "agent_selection" }]
  ];
}

// =============================================================================
// LIVELLO 2: LISTA CATEGORIE (get_active_sop, get_active_ser, get_active_pro)
// =============================================================================
else if (cbData === "get_active_sop" || cbData === "get_active_ser" || cbData === "get_active_pro") {
  const macro = cbData.split("_")[2].toUpperCase(); 
  text = `${t.cat_title} [${macro}]\n━━━━━━━━━━━━━━━━━━━━\nScegli un ambito specifico:`;

  catalog.filter(c => c.macrocategories === macro).forEach(cat => {
    buttons.push([{ 
      text: cat.short_name || cat.name, 
      callback_data: `get_active_${macro.toLowerCase()}_${cat.callback_data}` 
    }]);
  });
  buttons.push([{ text: t.btn_back, callback_data: "get_active" }]);
}

// =============================================================================
// LIVELLO 3: LISTA PROCEDURE (Con Stato + Legenda)
// =============================================================================
else if (cbData.includes("_CAT_")) {
  const macro = cbData.split("_")[2];
  const catId = "CAT_" + cbData.split("_CAT_")[1]; 
  const category = catalog.find(c => c.callback_data === catId);

  if (category) {
    // Componiamo il testo: Titolo + Corpo + Legenda
    text = `${t.svc_title}\n<b>${category.short_name.toUpperCase()}</b>\n━━━━━━━━━━━━━━━━━━━━\nCosa vuoi SuperVisionare?${t.legend}`;

    category.subcategories.forEach(sub => {
      // Verifica se il blueprint è pronto
      const isReady = sub.blueprint_ready === true;
      const statusIcon = isReady ? "🟢 " : "⚪ "; 

      buttons.push([{ 
        text: `${statusIcon}${sub.short_name || sub.name}`, 
        callback_data: `get_active_${macro}_${sub.callback_data}` 
      }]);
    });
    buttons.push([{ text: t.btn_back, callback_data: `get_active_${macro}` }]);
  }
}

// =============================================================================
// LIVELLO 4: TERMINALE (Contiene _SVC_) -> EXECUTION FLAG
// =============================================================================
else if (cbData.includes("_SVC_")) {
  const skuId = "SVC_" + cbData.split("_SVC_")[1];
  return [{
    json: {
      ...item,
      action: "execute_blueprint",
      sku_id: skuId,
      chat_id: chatId,
      message_id: messageId,
    }
  }];
}

// =============================================================================
// FALLBACK
// =============================================================================
if (text === "") {
    text = "⚠️ Errore di navigazione. Torna al menu principale.";
    buttons = [[{ text: "🏠 Menu Principale", callback_data: "agent_selection" }]];
}

// =============================================================================
// OUTPUT PER TELEGRAM
// =============================================================================
return [{
  json: {
    telegramApiPayload: {
      method: "editMessageText",
      chat_id: chatId,
      message_id: messageId,
      text: text,
      parse_mode: "HTML",
      reply_markup: { inline_keyboard: buttons }
    }
  }
}];

// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_Blueprint_Missing_Message (Full Logic v2.1)
// DESC: Genera ASH dinamico e apre WebApp con parametri completi
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;

// 1. Recupero basi dati e config URL
const catalog = item.service_catalog_setup || {};
const userReq = item.user_request || {};
const owner = item.owner_data || {};
const baseUrl = item.urlMiniApp || "https://trinaibusinessoperatingsystem.github.io/SiteBoS-MiniApp/telegram_control/";

const skuId = userReq.ghost_id;
const categoryId = userReq.category_id;
const chatId = item.chat_id || (item.body?.callback_query?.message?.chat?.id) || owner.chat_id;
const messageId = item.message_id || (item.body?.callback_query?.message?.message_id);

// --- 2. LOGICA GENERAZIONE ASH (Allineata a Dashboard) ---
function generateSignature(str, key) {
    let hash = 0; const combined = str + key;
    for (let i = 0; i < combined.length; i++) {
        const char = combined.charCodeAt(i);
        hash = ((hash << 5) - hash) + char; hash = hash & hash; 
    }
    return Math.abs(hash).toString(16);
}

const SECRET_KEY = 'TrinAI-Autorize-Transaction-2=2&';
const ts = Date.now().toString();
// Usiamo il payload standard del tuo sistema
const payloadASH = `${chatId}|${ts}|ef4aece4-9ec0-4026-a7a7-328562bcbdf6`;
const ash = `${Buffer.from(payloadASH).toString('base64')}.${generateSignature(payloadASH, SECRET_KEY)}`;

// 3. Lookup Intelligente nel Catalogo per i nomi umani
let skuName = skuId; 
let categoryName = "Area selezionata"; 
let macro = "sop"; 

if (catalog.categories && Array.isArray(catalog.categories)) {
    const currentCategory = catalog.categories.find(cat => cat.callback_data === categoryId);
    if (currentCategory) {
        categoryName = currentCategory.short_name || currentCategory.name.replace(/\[.*?\]/g, '').trim();
        macro = (currentCategory.macrocategories || "SOP").toLowerCase();
        if (currentCategory.subcategories) {
            const currentProcedure = currentCategory.subcategories.find(sub => sub.callback_data === skuId);
            if (currentProcedure) {
                skuName = currentProcedure.short_name || currentProcedure.name;
            }
        }
    }
}

// 4. Costruzione messaggi localizzati
const rawLang = (owner.lenguage || 'it').toLowerCase();
let lang = rawLang.includes('en') ? 'en' : 'it';

const translations = {
  'it': {
    title: "🛠️ <b>CONFIGURAZIONE NECESSARIA</b>",
    msg: `La voce <b>"${skuName}"</b> (<i>${categoryName}</i>) non è ancora attiva.`,
    explanation: "Dobbiamo configurare le istruzioni e i parametri AI per renderla operativa.",
    btn_activate: "🚀 Configura e Attiva Ora",
    btn_back: `⬅️ Torna a ${categoryName}`
  },
  'en': {
    title: "🛠️ <b>CONFIGURATION REQUIRED</b>",
    msg: `The item <b>"${skuName}"</b> (<i>${categoryName}</i>) is not active yet.`,
    explanation: "We need to configure instructions and AI parameters to make it operational.",
    btn_activate: "🚀 Configure & Activate Now",
    btn_back: `⬅️ Back to ${categoryName}`
  }
};

const t = translations[lang];

// 5. Costruzione URL WebApp con i parametri corretti (AGGIUNTO message_id)
const fullWebAppUrl = `${baseUrl}add-product.html?ash=${ash}&catId=${categoryId}&ghostId=${skuId}&msg_id=${messageId}`;
const backCallback = `get_active_${macro}_${categoryId}`;

return [{
  json: {
    telegramApiPayload: {
      method: "editMessageText",
      chat_id: chatId,
      message_id: messageId,
      text: `${t.title}\n━━━━━━━━━━━━━━━━━━━━\n\n${t.msg}\n\n${t.explanation}`,
      parse_mode: "HTML",
      reply_markup: {
        inline_keyboard: [
          [{ text: t.btn_activate, web_app: { url: fullWebAppUrl } }],
          [{ text: t.btn_back, callback_data: backCallback }]
        ]
      }
    }
  }
}];

// NODO: Context_Preparer
// Questo nodo prepara l'input per il Context_Reducer v3.0

const item = $input.first().json;
const catalog = item.service_catalog_setup;

// 1. Identifichiamo il target (Ghost ID)
// Lo prendiamo dallo sku_id che è già presente nel tuo JSON
const targetSku = item.sku_id; 

let foundCatId = null;

// 2. Troviamo a quale categoria appartiene questo sku_id
// Cicliamo il catalogo per trovare la corrispondenza
if (catalog && catalog.categories) {
    for (const category of catalog.categories) {
        const subFound = category.subcategories.find(sub => sub.callback_data === targetSku);
        if (subFound) {
            foundCatId = category.callback_data;
            break;
        }
    }
}

// 3. Costruiamo l'oggetto user_request come richiesto dal riduttore
// Se non lo troviamo nel catalogo (perché magari è un click su categoria), 
// cerchiamo di dedurlo dal corpo della callback
const user_request = {
    category_id: foundCatId || (item.body.callback_query.data.includes('CAT_') ? item.body.callback_query.data : null),
    ghost_id: targetSku || null
};

// Se non troviamo la categoria, lanciamo un errore per evitare il crash del nodo successivo
if (!user_request.category_id) {
    throw new Error("Impossibile determinare la Category ID dall'input fornito.");
}

// 4. Restituiamo l'oggetto originale arricchito con user_request
return {
    json: {
        ...item,
        user_request: user_request
    }
};

// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_Blueprint_Execution_Final_v5.3
// DESC: Layout Enterprise con supporto FIRMA DIGITALE (SIGNATURE)
// ═══════════════════════════════════════════════════════════════

const fItem = $input.first().json;

// 1. Recupero Dati Core
const bObj = fItem.Final_Blueprint || {};
const pObj = fItem.Final_Product || {};
const oInfo = fItem.owner_data || {};
const uReq = fItem.user_request || {};
const catalog = fItem.service_catalog_setup?.categories || [];

// Recupero la base URL e coordinate messaggio
const baseUrl = fItem.urlMiniApp || "https://trinaibusinessoperatingsystem.github.io/SiteBoS-MiniApp/telegram_control/"; 
const mId = fItem.message_id || (fItem.body?.callback_query?.message?.message_id);

// 2. LOGICA DETERMINISTICA DI CATEGORIZZAZIONE
const categoryId = uReq.category_id || pObj.identity?.category;
const currentCat = catalog.find(cat => cat.callback_data === categoryId);

let mKey = (currentCat?.macrocategories || bObj.blueprint_type || "SOP").toUpperCase();
if (mKey === "INTERNAL_PROTOCOL") mKey = "SOP";
if (mKey === "SERVICE") mKey = "SER";
if (mKey === "PRODUCT") mKey = "PRO";

// 3. Matrice di Comunicazione Enterprise
const matrix = {
  'SOP': {
    it: { title: "⚙️ <b>SOP: PROTOCOLLO INTERNO</b>", body: "Standard operativo certificato per l'esecuzione interna.", label: "PUNTI DI CONTROLLO INTERNI:" },
    en: { title: "⚙️ <b>SOP: INTERNAL PROTOCOL</b>", body: "Certified operational standard for internal execution.", label: "INTERNAL CONTROL POINTS:" }
  },
  'SER': {
    it: { title: "🛠️ <b>SER: EROGAZIONE SERVIZIO</b>", body: "Modulo di workflow pronto per la delivery professionale.", label: "MILESTONE DI EROGAZIONE:" },
    en: { title: "🛠️ <b>SER: SERVICE DELIVERY</b>", body: "Workflow module ready for professional delivery.", label: "DELIVERY MILESTONES:" }
  },
  'PRO': {
    it: { title: "📦 <b>PRO: UNITÀ PRODOTTO</b>", body: "Parametri di conformità e controllo qualità prodotto.", label: "CONTROLLI QUALITÀ PRODOTTO:" },
    en: { title: "📦 <b>PRO: PRODUCT UNIT</b>", body: "Product compliance and quality control parameters.", label: "PRODUCT QUALITY CHECKS:" }
  }
};

// 4. Lingua e Label Evidenze (Incluso SIGNATURE)
const L = (oInfo.lenguage || 'it').toLowerCase().includes('en') ? 'en' : 'it';
const tF = {
  ...matrix[mKey][L],
  back: L === 'it' ? "⬅️ Lista" : "⬅️ List",
  guided: L === 'it' ? "🚀 Certifica Passo-Passo" : "🚀 Step-by-Step",
  setup: L === 'it' ? "⚙️ Configurazione" : "⚙️ Setup",
  // Mappatura Icone per il menu
  evLabels: { 
    "VISION": "📸 Foto Live", 
    "FILE": "📄 Documento", 
    "TEXT": "📝 Validazione",
    "SIGNATURE": "✍️ Firma Digitale" // <-- Nuova gestione firma
  }
};

// 5. Logica ID per URL
const cleanGhostId = (uReq.ghost_id || bObj.service_sku || pObj.identity?.item_sku || "").toUpperCase();

let keyboard = [];
let summary = "";

// 6. Certificazione Guidata
keyboard.push([{ text: tF.guided, callback_data: `ge_si=${cleanGhostId}` }]);

// 7. Generazione Automatica Bottoni per ogni Step del Blueprint
if (bObj.stages) {
  bObj.stages.forEach(stg => {
    stg.steps.forEach(stp => {
      if (stp.quality_check?.is_required) {
        const type = (stp.quality_check.evidence_type || "VISION").toUpperCase();
        const icon = tF.evLabels[type] || "✔️";

        // URL MiniApp: passiamo evidence_type affinché certificator.html si adatti
        const url = `${baseUrl}certificator.html?sop_id=${cleanGhostId}&step_id=${stp.step_id}&message_id=${mId}&evidence_type=${type}`;

        keyboard.push([{ text: `${icon}: ${stp.step_name}`, web_app: { url: url } }]);
        summary += `• <b>${stp.step_name}</b> (<i>${type}</i>)\n`;
      }
    });
  });
}

// 8. Footer Navigazione
keyboard.push([
  { text: tF.back, callback_data: `get_active_${mKey.toLowerCase()}_${categoryId}` },
  { text: tF.setup, callback_data: `open_blueprint_build_${cleanGhostId}` }
]);

// --- AGGIUNTA PULSANTE HOME GLOBALE ---
keyboard.push([
  { text: "🏠 Home", callback_data: "agent_selection" }
]);

// 9. Composizione Messaggio Finale
const msgText = `
${tF.title}
━━━━━━━━━━━━━━━━━━━━
${tF.body}

<b>"${bObj.blueprint_name || pObj.identity?.item_name || 'Protocollo'}"</b>
<i>${bObj.blueprint_description || 'Nessuna descrizione.'}</i>

${tF.label}
${summary || "Nessuna azione richiesta."}
━━━━━━━━━━━━━━━━━━━━
👇 <b>Seleziona la milestone da certificare:</b>`;

// 10. Output Finale
return [{
  json: {
    ...fItem,
    telegramApiPayload: {
      method: "editMessageText",
      chat_id: oInfo.chat_id,
      message_id: mId,
      text: msgText,
      parse_mode: "HTML",
      reply_markup: { inline_keyboard: keyboard }
    }
  }
}];

